options.customCss:
:root {

	/* Page Background */
	--color-background: #eaf1ff;

	/* Main Form Card */
	--color-card-bg: #ffffff;
	--color-card-border: #d9e2f2;
	--color-card-shadow: rgba(0,0,0,0.12);

	/* Button */
	--color-submit-btn-bg: #5a4cc2;
	--color-submit-btn-text: #ffffff;

	/* Text */
	--color-header: #2f3440;
	--color-label: #444444;
	--color-header-subtext: #6b7280;

	/* Inputs */
	--color-input-border: #d6dbea;
	--color-input-text: #50545a;
	--color-focus-border: #5a4cc2;

	/* Card Style */
	--border-radius-card: 14px;
	--border-radius-input: 8px;

	/* Layout */
	--padding-container-top: 40px;
	--container-width: 520px;

	/* Strong shadow to separate form */
	--box-shadow-card: 0px 18px 40px rgba(0,0,0,0.15);
}

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "resume_screening_eveluation": {
      "type": "object",
      "description": "Analyse a candidate's resume against a job description and outputs strengths, weaknesses, risk/reward assessment, overall fit score, and justification for the rating.",
      "properties": {
        "candidate_strength": {
          "type": "array",
          "description": "A list of specific strengths or qualifications that match the job requirements.",
          "items": {
            "type": "string"
          }
        },
        "candidate_weakness": {
          "type": "array",
          "description": "A list of areas where the candidate falls short or lacks alignment with the job requirements.",
          "items": {
            "type": "string"
          }
        },
        "risk_factor": {
          "type": "object",
          "description": "An evaluation of the potential downside of hiring this candidate.",
          "properties": {
            "score": {
              "type": "string",
              "enum": ["low", "medium", "high"],
              "description": "Risk level associated with hiring the candidate."
            },
            "explanation": {
              "type": "string",
              "description": "Explanation of the worst-case risk scenario if the candidate is hired."
            }
          }
        },
        "reward_factor": {
          "type": "object",
          "description": "An evaluation of the potential upside of hiring this candidate.",
          "properties": {
            "score": {
              "type": "string",
              "enum": ["low", "medium", "high"],
              "description": "Reward or upside potential if the candidate performs well."
            },
            "explanation": {
              "type": "string",
              "description": "Explanation of the best-case scenario if the candidate is hired."
            }
          }
        },
        "overall_fitting": {
          "type": "integer",
          "description": "A rating from 0 to 10 indicating how well the candidate matches the job description.",
          "minimum": 0,
          "maximum": 10
        },
        "rating_justification": {
          "type": "string",
          "description": "A concise explanation summarizing why the candidate received the overall_fitting score. It should reference key strengths, weaknesses, and risk/reward considerations that influenced the rating."
        }
      }
    }
  }
}
